      <View style={styles.buttonRow}>
        <ActionButton
          title={`Density: ${preferences.displayDensity === 'comfortable' ? 'Compact' : 'Comfortable'}`}
          onPress={() =>
            updatePreference(
              'displayDensity',
              preferences.displayDensity === 'comfortable' ? 'compact' : 'comfortable'
            )
          }
          color="#E67E22"
        />
        <ActionButton title="Clear Searches" onPress={clearSearches} danger />
      </View>
